using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: returns JsonTypeInfo<Person> directly.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

// 2) Probe without throwing: TryGetTypeInfo returns false if unavailable.
//    Here we use options with NO resolver, so nothing is resolvable.
var empty = new JsonSerializerOptions { TypeInfoResolver = null };

if (empty.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    Console.WriteLine($"Found metadata: {info!.Type.Name}");
}
else
{
    Console.WriteLine("No metadata available for Person (no exception thrown).");
}

// Positive probe with the configured options:
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info2))
{
    Console.WriteLine($"Positive probe succeeded: {info2!.Type.Name}");
}

record Person(string Name, int Age);

